conditional.example:
{{#if ENABLE_DEBUG}}
// Debug code
{{#elif DEBUG_LEVEL > 5}}
// Verbose debug
{{else}}
// No debug
{{/if}}

loops.nested_example:
{{#for outer in OUTER}}
  {{#for inner in INNER}}
    #define MACRO_{{outer}}_{{inner}}
  {{/for}}
{{/for}}

inline.example:
{{#for level in "1|2|3|4|5|6"|split|pipe}}
  {{AWK:
    BEGIN {
      level = ENVIRON["level"]
      printf "#define LEVEL_%s\n", level
    }
  }}
{{/for}}

loop_variables.example:
{{#for entry in ARRAY}}
  {{AWK:
    BEGIN {
      entry_value = ENVIRON["entry"]
      print entry_value
    }
  }}
{{/for}}
